  SELECT COUNT(*),
         string_agg(format('%s (existing id %s)', expected.domain, o.id::text), ', ')
    INTO v_count, v_examples
    FROM expected
    JOIN public.organizations o ON o.domain = expected.domain
   WHERE o.id <> expected.expected_id;

  IF v_count > 0 THEN
    RAISE EXCEPTION USING
      MESSAGE = format('Seed pre-flight: %s existing organisations have domains the seed wants to insert with different ids: %s', v_count, v_examples),
      HINT = 'See supabase/seed/README.md "Pre-clean for partial-state DBs" before retrying.';
  END IF;
END $preflight$;

